class Solution {
public:
    char repeatedCharacter(string s) {
        unordered_set<char> seen;
        for (char c : s) {
            if (seen.find(c) != seen.end()) {
                return c;
            }
            seen.insert(c);
        }
        return '\0'; // This line will never be reached according to the problem constraints
    }
};
```

